-- Question 15: Digoxin dose adjustment in renal impairment
UPDATE questions SET
  is_trial_featured = TRUE,
  trial_display_order = 15,
  explanation_structured = '{
    "summary": "Digoxin is primarily excreted unchanged by the kidneys, so patients with reduced renal function (eGFR 25 mL/min) require significant dose reduction to prevent accumulation and toxicity.",
    "key_points": [
      "70% of digoxin is excreted unchanged in urine",
      "Digoxin has a narrow therapeutic index (1.0-2.0 ng/mL for most indications)",
      "Toxicity signs include nausea, visual disturbances (yellow vision), and arrhythmias",
      "Dose reduction of 50% or more may be needed in severe renal impairment"
    ],
    "clinical_pearl": "In renal impairment, reduce digoxin dose and increase monitoring. Check digoxin levels 6 hours post-dose. Also monitor potassium - hypokalemia increases digoxin toxicity risk.",
    "why_wrong": {
      "B": "Aspirin is metabolized hepatically to salicylic acid. While high doses should be avoided in renal impairment, standard low-dose aspirin does not require adjustment.",
      "C": "Atorvastatin is hepatically metabolized and does not require dose adjustment in renal impairment.",
      "D": "Levothyroxine dosing is based on thyroid function tests, not renal function, as it is not renally cleared.",
      "E": "Loratadine is primarily hepatically metabolized and does not require significant dose adjustment in renal impairment."
    },
    "exam_tip": "Drugs needing renal dose adjustment often end in ''-mycin'' (aminoglycosides), ''-cillin'' (some penicillins), and include digoxin, lithium, metformin, and DOACs. Check BNF renal appendix!",
    "related_topics": ["renal-impairment", "dose-adjustment", "digoxin-toxicity"]
  }'::jsonb
WHERE id = '89261e5e-4f14-4aaa-b741-eddf97dbf84f';

-- Question 16: Schedule 2 controlled drugs
UPDATE questions SET
  is_trial_featured = TRUE,
  trial_display_order = 16,
  explanation_structured = '{
    "summary": "Schedule 2 controlled drugs (like morphine, oxycodone, fentanyl) require pharmacies to maintain detailed registers recording all receipts and supplies, which must be kept for 2 years.",
    "key_points": [
      "Schedule 2 includes opioids (morphine, diamorphine, fentanyl) and stimulants (amphetamines)",
      "CD register entries must be made within 24 hours and include quantity, form, and supplier/patient details",
      "Registers must be bound books with no erasures (mistakes should be crossed out and dated)",
      "Records must be kept for 2 years from the last entry date"
    ],
    "clinical_pearl": "When running balances do not match physical stock, a discrepancy must be investigated and documented. Regular stock checks (ideally daily) help identify discrepancies early.",
    "why_wrong": {
      "A": "Schedule 1 drugs (LSD, cannabis, ecstasy) have no recognized medical use in the UK and are not held in community pharmacies.",
      "C": "Schedule 3 drugs (buprenorphine, temazepam, tramadol) require safe custody but not CD register entries.",
      "D": "Schedule 4 drugs (benzodiazepines, anabolic steroids) have minimal record-keeping requirements beyond normal POM records.",
      "E": "Schedule 5 drugs (low-strength codeine preparations, some cough medicines) can be sold OTC with minimal restrictions."
    },
    "exam_tip": "CD schedules: S1 = no medical use, S2 = full controls + register, S3 = safe custody (usually) but no register, S4/S5 = minimal controls. Remember ''STOMP'' for S2: Strong opioids, True amphetamines.",
    "related_topics": ["controlled-drugs", "pharmacy-law", "record-keeping"]
  }'::jsonb
WHERE id = '06f868c9-79f5-4330-8d92-d4aaa2599d1c';

-- Question 17: First-pass metabolism - Morphine
UPDATE questions SET
  is_trial_featured = TRUE,
  trial_display_order = 17,
  explanation_structured = '{
    "summary": "Morphine undergoes extensive first-pass metabolism in the liver, reducing its oral bioavailability to approximately 30%. This is why oral morphine doses are much higher than parenteral doses.",
    "key_points": [
      "First-pass metabolism occurs as drug passes through gut wall and liver before reaching systemic circulation",
      "Morphine is converted to morphine-3-glucuronide (inactive) and morphine-6-glucuronide (active)",
      "Oral:parenteral dose ratio for morphine is approximately 3:1",
      "Other high first-pass drugs include GTN, propranolol, and verapamil"
    ],
    "clinical_pearl": "When converting morphine from IV to oral, multiply the IV dose by 3. For example, 10mg IV morphine = approximately 30mg oral morphine.",
    "why_wrong": {
      "B": "Furosemide has variable oral absorption (50-70%) but this is due to poor absorption rather than first-pass metabolism.",
      "C": "Levothyroxine has low bioavailability (40-80%) due to incomplete absorption, not first-pass metabolism.",
      "D": "Alendronate has very low bioavailability (<1%) due to poor absorption from the GI tract, not first-pass metabolism.",
      "E": "Ibuprofen is well absorbed with minimal first-pass metabolism and has approximately 80-100% bioavailability."
    },
    "exam_tip": "High first-pass metabolism drugs: GTN (why given sublingual), morphine, propranolol, lidocaine (not given orally), and some statins. These often need alternative routes or higher oral doses.",
    "related_topics": ["pharmacokinetics", "bioavailability", "opioid-dosing"]
  }'::jsonb
WHERE id = 'a93245d9-25e1-4598-9e3c-118474446572';

